const Q_ECONOMICS_2021_MODEL_I=[{"id": "objective>Economics>2021 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the economic term used to describe the benefit forgone when a choice is made?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Scarcity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Explicit cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Scale of preference</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity cost is the forgone benefit that would have been derived by an option not chosen. To properly evaluate opportunity costs, the costs and benefits of every option available must be considered and weighed against the others.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2021 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A shift in the demand curve to the left illustrates</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A decrease in demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in quantity demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in quantity demanded</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is a decrease in demand curve when  the curve shift inward or leftward ( to the left) also the quantity will decrease.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2021 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If supply curve is horizontal, the price elasticity of supply is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Infinite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Greater than 0 but less than 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Greater than 1 but less than infinity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The price elasticity of supply measures how the quantity supplied responds to changes in the price. If the supply curve is horizontal, it means that suppliers are willing and able to sell any amount at a certain price. This implies that the quantity supplied is perfectly elastic, or in other words, the price elasticity of supply is infinite. This is because even a small change in price leads to a very large change in the quantity supplied.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2021 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major function of the price mechanism is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Guide consumers to minimise satisfaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ensure that producers maximise profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ensure efficient allocation of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase scarcity of productive resources</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Functions of price mechanism are; <br/> - it determines the amount of reward accruing to the various factors of production <br/> - it indicates changes in demand or changes in  the wants of consumers <br/> - it determines how scarce goods and services are allocated <br/> - it determines the allocation of scarce productive resource <br/> - it influences the  types of goods and services that will be produced in an  economy</div>", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE"}, {"id": "objective>Economics>2021 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer question below <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> - Which of the curves represents the monoploy demand curve? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The demand curve of a monopoly is also the Average revenue curve which slopes downward.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2021 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer question below <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> - What is the point e on the diagram?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equilibrium point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tangential point</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The \"e\" point on the curve is the equilibrium point of a monopoly where the MC cuts the MR from below.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2021 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer question below <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> - The equilibrium price and quantity respectively are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">OP1, OQ1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OC, OB</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OP1, OB</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OC, OQ1</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the curve above , the equilibrium price is OP or OP1 while the equilibrium quantity is OQ1 or OQ.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2021 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the short run when the total product is maximum</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Average product and marginal product are equal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal product is rising</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Average product is rising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal product is equal to zero</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the Total product is at maximum, Marginal product is zero and when Total product falls, Marginal product is negative.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2021 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The profit maximising rule for all firms is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MC >MR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC =MR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC < MR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">TR > TC</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The profit maximizing rule for all firms is MC = MR, where MC stands for Marginal Cost and MR stands for Marginal Revenue. This rule states that to maximize profit, a firm should produce up to the point where the cost of producing an additional unit (MC) is equal to the revenue gained from selling that additional unit (MR). Beyond this point, the cost of producing additional units will exceed the revenue gained from selling them, leading to a decrease in profit.</div>", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION"}, {"id": "objective>Economics>2021 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given the consumption function for an economy as C=150+0.8Y, and Y=C+S, the marginal propensity to save (MPS) is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.6</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C=150+0.8Y <br/> Where 0.8 = MPC(b) <br/> Therefore, MPS = 1 - MPC <br/>                           MPS = 1 - 0.8 <br/>                                         = 0.2</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : SAVINGS FUNCTION"}, {"id": "objective>Economics>2021 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT a function of a deposit money bank?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Accepting deposits of money and savings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Buying and selling shares for their customers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Granting loans and advances</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Issuing bank notes and coins</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deposit bank play an important function in the development and growth of a nation. The principle role carried out by deposit money banks is to ensure there is adequate flow of money to service deficit sectors of the economy and facilitate the movement of funds amongst economic units.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2021 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristics of developing countries, EXCLUDE</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Low labour productivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low level of employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low level of illiteracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Low per capita income</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The features or characteristics of developing countries are: <br/> - Dependence on agriculture <br/> - high dependency on foreign nations <br/> - Low savings and investment <br/> - Population explosion <br/> - low per capita income <br/> - high level of illiteracy <br/> - high rate of importation <br/> - high level of unemployment <br/> - low standard of living.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2021 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are arguments in support of trade protection, EXCEPT to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Protect and expand domestic employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Protect infant industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Correct balance of payments deficits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Promote globalisation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Argument to protect trade protection are: <br/> - Prevent dumping <br/> - Protect infant industries <br/> - Protect and expand domestic employment <br/> - Correct balance of payment deficits <br/> -Limit over-specialisation <br/> - help the environment <br/> - Save jobs</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2021 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A linear equation connecting consumption expenditure and disposable income expresses</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Consumption function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aggregate consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Average propensity to consume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Autonomous consumption function</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumption function is a mathematical relationship between the level of income and consumption. Keynes called this positive relationship between consumption expenditure and disposable income the consumption function and it is written as : C= F(Y) or C = F (Yd).  The definitional equation can be written as: C = a +byd</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : CONSUMPTION FUNCTION"}, {"id": "objective>Economics>2021 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use of taxation and government expenditure to influence the performance of the economy is called .................policy</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Exchange rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commercial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monetary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy is the use of government revenue collection (taxes or tax cuts) and expenditure to influence a country's economy.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2021 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are functions of any economic system, EXCEPT </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Economic stability </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Allocation of resources </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Production efficiency and equity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Organisation of production </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The type of economic system practised in any society or nation depends on the way the available productive resources are owned and the way society takes decisions on issues relating to the basic economic problems. It is the ownership of the means of production, how the choice is made  and by whom that determines the type of economic system.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2021 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT a source of funding for a partnership? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Contribution from members </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Issuance of shares </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benefit from credit facilities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Re-investment of profits </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The source of capital for partnership are: <br/> - Personal contributions from partners <br/> - Loans and overdraft <br/> - Trade credit <br/> - Undistributed profit <br/> - Admission of new partners</div>", "topic": "BUSINESS ORGANISATION : PARTNERSHIP"}, {"id": "objective>Economics>2021 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reorganisation of a public entity to make it self-accounting outside of government support is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Commercialisation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Privatisation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nationalisation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Industrialisation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercialisation  is a policy geared towards making state-owned enterprises to become more efficient and profit-oriented. The policy makes it possible for public enterprises to become more viable and effective.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2021 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The price of a commodity increases from #5 to #7 while the quantity demanded decreases from 20kg to 16kg. What type of price elasticity of demand is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Perfectly elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Perfectly inelastic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using e = ∆QD/∆P  x  P/QD <br/> Where ∆QD = q2 - q1 <br/>                ∆P = p2 - p1 <br/>                  P =  first price <br/>                   Q = First quantity <br/>  <br/> Therefore,   e =  20 - 16/ 7-5  x 5/20 <br/>                             e = -4/2  x 5/20 <br/>                               e = - 0.5  Note that price elasticity of demand is always positive <br/> Therefore, e = 0.5 which is less than 1.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2021 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the mean from the observation: 18, 24, 16, 30, 12, 20 , 14 and 10</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18</div>", "<div style=\"font-family:Cambria;font-size:17px;\">81</div>", "<div style=\"font-family:Cambria;font-size:17px;\">144</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mean of a set of numbers is calculated by adding all the numbers and then dividing by the count of those numbers. For the given set of numbers, the mean is (18+24+16+30+12+20+14+10)/8 = 18. Therefore, the correct answer is 18.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2021 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follow <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The curve labelled \"Q\" is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">variable cost</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The curve labelled \"Q\" represent the  fixed cost from the diagram </div>", "topic": "THE CONCEPT OF COST & REVENUE : CONCEPT"}, {"id": "objective>Economics>2021 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a measure used to control deflation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase in wages and salaries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reduction in bank rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Use of budget deficit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Use of budget surplus </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deflation is a decrease in the general price level of goods and services. It can be controlled by measures that increase the money supply or demand in the economy. Increasing wages and salaries, reducing bank rates, and using a budget deficit are all measures that can increase demand or money supply, and thus combat deflation. On the other hand, using a budget surplus is not a measure to control deflation. A budget surplus, which involves the government spending less than it earns, can actually reduce demand and exacerbate deflation.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2021 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sum of #5,000 is deposited into a bank and the reserve ratio is 10%. Calculated the total sum of money the bank can create from the deposit.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">Amount</td><td style=\"text-align:center;\">created=</td><td style=\"text-align:center;\">cash deposit<hr size=\"1\" />cash ratio</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5000<hr size=\"1\" />10%</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5000<hr size=\"1\" />0.1</td><td style=\"text-align:center;\">=50,000</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>                             </div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2021 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a bus owner's monthly income increases from #14,000 to #18,000 and as a result of this, his consumption increases from #950 to #1150. Calculate the marginal propensity to consume</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.02</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.03</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.04</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.05</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">MPC = ∆C/ ∆Y <br/>         ∆C = 1150 - 950 = 200 <br/>          ∆Y = 18000 - 14000 = 4000 <br/> MPC = 200/4000 <br/>                       = 0.05</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : CONSUMPTION FUNCTION"}, {"id": "objective>Economics>2021 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The international Bank for Reconstruction and Development (IBRD) was established in the year</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1940</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1942</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1944</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1950</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The International Bank for Reconstruction and Development (IBRD), which is part of the World Bank Group, was established in 1944.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}, {"id": "objective>Economics>2021 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are problems of economic development in Nigeria except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Corruption and nepotism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inadequate capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inadequate data</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Political stability</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The problems are: <br/> - Low level of savings <br/> - Lack of infrastructural facilities <br/> - Political instability <br/> - Population explosion  etc</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2021 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are positive contributions of petroleum to the Nigerian economy except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">development of mon-economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">employment generation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign exchange earning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infrastructural development</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The positive contributions are: <br/> - source of government revenue <br/> - generation of employment <br/> - infrastructural development <br/> - source of foriegn exchange  etc.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2021 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Terms of trade can be defined as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">balance of payment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance of trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the difference between export prices and inport prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ratio of export prices to that of import prices</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Terms of trade is an economic concept that refers to the relative price of exports in terms of imports and is defined as the ratio of export prices to import prices. It can be interpreted as the amount of import goods an economy can purchase per unit of export goods.</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>2021 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The money value of the total volume of goods and services produced in a given country at a particular period of time is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Disposable income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gross Domestic Product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gross National Product</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">National income is the total volume of goods and services produced in a given economy at a given period of time.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2021 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a measure used in controlling monopoly?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Legalizing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Level of technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Patent Law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Price control</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monopoly can be controlled or regulated by: Anti-monopoly laws e,g tariff, through taxation, through price regulation or control.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2021 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of following is not a reason for taxation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Generation of revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prevention of dumping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Promotion of economic growth and development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Promotion of National debt </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reasons or why governemt impose tax are: <br/> - to raise revenue <br/> - to redistribute income <br/> -  to control inflation <br/> - to protect infant industries <br/> - to correct and adverse balance of payment <br/> - to prevent dumping  etc.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>2021 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The graph that shows combination of two or more commodities that yield the same level of satisfaction is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indifference curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal utility curve</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Indifference curve is a combination of two commodities which a consumer consume which gives the same level of satisfaction.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : INDIFFERENCE CURVE"}, {"id": "objective>Economics>2021 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An economy system whose production and distribution of goods and services are centrally planned is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capitalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">traditionalist</div>", "<div style=\"font-family:Cambria;font-size:17px;\">socialism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feudalism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Socialism is also known as command economy or centrally planned economy. It is an economy system in which the means of prodution are owned and controlled by the government or state.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2021 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The assembly of different components of a particular car into a unit whole is carried out by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">construction industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mining industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">processing industry</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Constructive industry is concerned with all the activities of those who engage in assembling of goods manufactured into useable form. </div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2021 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of velocity of money was propounded by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Adam smith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alfred marshal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Irving fisher</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lionel Robbins</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity of money also known as the equation of money was propounded by Sir Irving Fisher which he represented by an equation: MV = PT</div>", "topic": "MONEY : INTRODUCTION"}, {"id": "objective>Economics>2021 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The agricultural programme that is aimed at increasing productivity by granting farmers access to large farm sizes is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Agricultural loan scheme</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Farm settlement scheme</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green Revolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Operation Feed the Nation </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Farm Settlement Scheme is an agricultural programme that is aimed at increasing productivity by granting farmers access to large farm sizes. This scheme was designed to encourage the youth to take up farming. It provides them with the necessary resources such as land, loans, and training to make farming profitable and attractive.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2021 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The agricultural policy of Operation Feed the Nation (OFN) was launched in the year</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1968</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1970</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1976</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1980</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Operation Feed the Nation was set up by General Olusegun Obasanjo's millitary regime between 1976 and 1979 inorder to increase food production and to popularise agriculture.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2021 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are functions of a retailer except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">advertising the goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bearing the risk of fall in prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bringing the goods nearer to consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">giving credit facilities to customers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The function of a retailer is to sell goods to the end user who is the consumer. Retailers perform various functions such as advertising the goods, bringing the goods nearer to consumers, and giving credit facilities to customers. However, bearing the risk of fall in prices is not a function of a retailer. This risk is typically borne by the wholesaler or the producer.</div>", "topic": "DISTRIBUTIVE TRADE : THE RETAILER"}, {"id": "objective>Economics>2021 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of a worker from Lagos to Abuja, to continue the same job is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">change of environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">division of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geographical mobility of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">occupational mobility of labour</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of a worker from one geographical location to another to continue the same job is known as geographical mobility of labour. This involves the ability of workers to move from one region to another in search of jobs. It does not involve a change in the type of job or occupation, which is referred to as occupational mobility of labour.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>2021 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the same basket of goods which cost #20 in previous year cost #15 in current year, calculate the price index</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">125</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Price index = Price index of current year/ Price of previous(base) year x 100 <br/>  <br/> Price Index = (15 / 20) x 100 <br/>  <br/> Price Index = 75</div>", "topic": "INFLATION & DEFLATION : INTRODUCTION"}];
